questionvariables.text:
/* V1: E-core with Center-Limb Air Gap */
/* Physical parameters */
mu0: 4*%pi/10^7;
N1_val: 200;
N2_val: 100;
mur_val: 2000;
lc_val: 0.4;
lg_val: 0.002;
Ac_val: 0.0004;
I0_val: 2;
f_val: 50;

/* Derived quantities — exact arithmetic */
omega_val: 2*%pi*f_val;
R_core: lc_val/(mur_val*mu0*Ac_val);
R_gap: lg_val/(mu0*Ac_val);
R_total: R_core + R_gap;

Phi_max: N1_val*I0_val/R_total;
emf_peak: N2_val*omega_val*Phi_max;

/* Error model values */
Phi_no_gap: N1_val*I0_val/R_core;
emf_no_omega: N2_val*Phi_max;
emf_wrong_N: N1_val*omega_val*Phi_max;

/* Numerical versions for display */
R_total_num: float(R_total);
Phi_max_num: float(Phi_max);
emf_peak_num: float(emf_peak);

/* Debug MCQ-MA options (checkbox) */
debug_opts: random_permutation([[1, false, "The formula R_core = ℓ_c/(μ_r·μ₀·A_c) was applied incorrectly"], [2, true, "The air gap reluctance was not included in the total reluctance"], [3, false, "The number of turns N₂ was correctly used in Faraday's law"], [4, true, "The derivative of sin(ωt) is missing the factor ω"], [5, false, "The cross-sectional area A_c was used correctly throughout"]]);
correct_errors: {2,4};

/* Teacher answers */
ta_reluctance: float(R_total);
ta_flux: float(Phi_max);
ta_emf: float(emf_peak);
ta_debug: correct_errors;

/* V2: C-core with Single Air Gap */
/* Physical parameters */
mu0: 4*%pi/10^7;
N1_val: 300;
N2_val: 150;
mur_val: 1500;
lc_val: 0.3;
lg_val: 0.001;
Ac_val: 0.0006;
I0_val: 1.5;
f_val: 60;

/* Derived quantities — exact arithmetic */
omega_val: 2*%pi*f_val;
R_core: lc_val/(mur_val*mu0*Ac_val);
R_gap: lg_val/(mu0*Ac_val);
R_total: R_core + R_gap;

Phi_max: N1_val*I0_val/R_total;
emf_peak: N2_val*omega_val*Phi_max;

/* Error model values */
Phi_no_gap: N1_val*I0_val/R_core;
emf_no_omega: N2_val*Phi_max;
emf_wrong_N: N1_val*omega_val*Phi_max;

/* Numerical versions for display */
R_total_num: float(R_total);
Phi_max_num: float(Phi_max);
emf_peak_num: float(emf_peak);

/* Debug MCQ-MA options (checkbox) */
debug_opts: random_permutation([[1, true, "The student used N₁ instead of N₂ in the Faraday's law step"], [2, false, "The total reluctance correctly includes both core and gap"], [3, false, "The derivative d(sin ωt)/dt = ω cos(ωt) was applied correctly"], [4, false, "The core permeability μ_r was omitted from the reluctance formula"], [5, true, "The sign of the induced EMF violates Lenz's law"]]);
correct_errors: {1,5};

/* Teacher answers */
ta_reluctance: float(R_total);
ta_flux: float(Phi_max);
ta_emf: float(emf_peak);
ta_debug: correct_errors;

/* V3: Toroid with Cut (Air Gap) */
/* Physical parameters */
mu0: 4*%pi/10^7;
N1_val: 500;
N2_val: 250;
mur_val: 3000;
lc_val: 0.5;
lg_val: 0.0015;
Ac_val: 0.0003;
I0_val: 1;
f_val: 50;

/* Derived quantities — exact arithmetic */
omega_val: 2*%pi*f_val;
R_core: lc_val/(mur_val*mu0*Ac_val);
R_gap: lg_val/(mu0*Ac_val);
R_total: R_core + R_gap;

Phi_max: N1_val*I0_val/R_total;
emf_peak: N2_val*omega_val*Phi_max;

/* Error model values */
Phi_no_gap: N1_val*I0_val/R_core;
emf_no_omega: N2_val*Phi_max;
emf_wrong_N: N1_val*omega_val*Phi_max;

/* Numerical versions for display */
R_total_num: float(R_total);
Phi_max_num: float(Phi_max);
emf_peak_num: float(emf_peak);

/* Debug MCQ-MA options (checkbox) */
debug_opts: random_permutation([[1, false, "The ω factor in the Faraday's law derivative was applied correctly"], [2, true, "The air gap reluctance was not included in R_total"], [3, true, "The student used N₁ instead of N₂ in the EMF calculation"], [4, false, "The cross-sectional area was doubled incorrectly"], [5, false, "The core reluctance formula is correct"]]);
correct_errors: {2,3};

/* Teacher answers */
ta_reluctance: float(R_total);
ta_flux: float(Phi_max);
ta_emf: float(emf_peak);
ta_debug: correct_errors;

/* V4: Rectangular Core with Two Series Air Gaps */
/* Physical parameters */
mu0: 4*%pi/10^7;
N1_val: 400;
N2_val: 200;
mur_val: 2500;
lc_val: 0.6;
lg_val: 0.002;
Ac_val: 0.0005;
I0_val: 1.8;
f_val: 60;

/* Derived quantities — exact arithmetic */
omega_val: 2*%pi*f_val;
R_core: lc_val/(mur_val*mu0*Ac_val);
R_gap: lg_val/(mu0*Ac_val);
R_total: R_core + R_gap;

Phi_max: N1_val*I0_val/R_total;
emf_peak: N2_val*omega_val*Phi_max;

/* Error model values */
Phi_no_gap: N1_val*I0_val/R_core;
emf_no_omega: N2_val*Phi_max;
emf_wrong_N: N1_val*omega_val*Phi_max;

/* Numerical versions for display */
R_total_num: float(R_total);
Phi_max_num: float(Phi_max);
emf_peak_num: float(emf_peak);

/* Debug MCQ-MA options (checkbox) */
debug_opts: random_permutation([[1, false, "The total reluctance correctly includes core and both gaps"], [2, false, "N₂ was correctly used in Faraday's law"], [3, true, "The derivative of sin(ωt) is missing the factor ω"], [4, false, "The core permeability was correctly included"], [5, true, "The sign of the EMF contradicts Lenz's law"]]);
correct_errors: {3,5};

/* Teacher answers */
ta_reluctance: float(R_total);
ta_flux: float(Phi_max);
ta_emf: float(emf_peak);
ta_debug: correct_errors;
